+fn backup_path_for(path: &Path) -> PathBuf {
+    let stamp = chrono::Utc::now().format("%Y%m%d_%H%M%S");
+    let file_name = path
+        .file_name()
+        .and_then(|name| name.to_str())
+        .unwrap_or("mcp-config.json");
+    path.with_file_name(format!("{file_name}.{stamp}.bak"))
+}
