+fn push_candidate(
+    out: &mut Vec<(McpConfigTool, PathBuf)>,
+    seen: &mut HashSet<(McpConfigTool, PathBuf)>,
+    tool: McpConfigTool,
+    path: PathBuf,
+) {
+    if path.as_os_str().is_empty() {
+        return;
+    }
+    let key = (tool, path.clone());
+    if seen.insert(key) {
+        out.push((tool, path));
+    }
+}
